fn route_request(req: &Request, backends: &[BackendConfig]) -> Result<Response, Error> {
    // Simple routing logic based on request path
    let backend_name = match req.uri().path() {
        "/service1" => "backend1",
        "/service2" => "backend2",
        _ => return Err(Error::from("No matching backend")),
    };

    // Find the backend configuration
    let backend = backends.iter().find(|b| b.name == backend_name).ok_or_else(|| {
        Error::from(format!("Backend {} not found", backend_name))
    })?;

    // Create a new request to the backend
    let mut backend_req = FastlyRequest::new(&backend.host, req.method(), req.uri())?;
    *backend_req.headers_mut() = req.headers().clone();

    // Set TLS configuration if needed
    if backend.tls {
        backend_req.set_tls(true)?;
        backend_req.set_sni(backend.sni)?;
    }

    // Send the request to the backend and receive the response
    let mut backend_res = backend_req.send_to_backend(backend.name)?;

    // Copy headers and status from backend response to FastlyResponse
    let mut res = FastlyResponse::new();
    *res.headers_mut() = backend_res.headers().clone();
    *res.status_mut() = backend_res.status();

    // Stream the body of the backend response to the client
    while let Some(data) = backend_res.body_stream().next() {
        res.append_data(&data?);
    }

    Ok(res)
}

